export function normalizeEffectActionType(value: unknown): string {
  return typeof value === "string" ? value.trim().toUpperCase() : "";
}

export function getEffectActionCatalogEntry(actionType: unknown): EffectActionCatalogEntry | undefined {
  return EFFECT_ACTION_CATALOG[normalizeEffectActionType(actionType)];
}

export function getKnownEffectActionTypes(): string[] {
  return Object.keys(EFFECT_ACTION_CATALOG).sort();
}

export function getEffectActionCatalog(): EffectActionCatalogEntry[] {
  return getKnownEffectActionTypes().map(actionType => EFFECT_ACTION_CATALOG[actionType]);
}
